import React, { useState } from 'react';
import { TextInput, Text, View } from 'react-native';

const InputField = () => {
  const [text, setText] = useState('');
  return (
    <View>
      <TextInput 
        style={{ borderBottomWidth: 1 }} 
        onChangeText={setText} 
        value={text} 
      />
      <Text>Typing: {text}</Text>
    </View>
  );
};
